def findSubsequenceCount(S, T):
    m = len(T)
    n = len(S)
    if m > n:
        return 0
    # Initialize a 2D list with zeros. Dimensions: (m+1) x (n+1)
    mat = [[0] * (n+1) for _ in range(m+1)]
    # Base case: for an empty T, there's one subsequence in any prefix of S
    for j in range(n+1):
        mat[0][j] = 1
    # Fill the DP table
    for i in range(1, m+1):
        for j in range(1, n+1):
            # If characters don't match, carry forward the value from the left
            if T[i-1] != S[j-1]:
                mat[i][j] = mat[i][j-1]
            else:
                # If they match, add two cases: 
                #   - subsequence without current character of S (left)
                #   - subsequence without the current character in both (diagonally up-left)
                mat[i][j] = mat[i][j-1] + mat[i-1][j-1]
    return mat[m][n]

