def numOfIncSubseqOfSizeK(arr, n, k):
    # Initialize a 2D dp list with k rows and n columns, all zeros.
    dp = [[0] * n for _ in range(k)]
    total = 0
    # Base case: for subsequences of length 1
    for i in range(n):
        dp[0][i] = 1
    # Fill dp for lengths from 2 to k
    for l in range(1, k):
        for i in range(l, n):
            # Initialize dp[l][i] to 0 (though already 0 by initialization)
            # Traverse all previous indices j from l-1 to i-1
            for j in range(l - 1, i):
                if arr[j] < arr[i]:
                    dp[l][i] += dp[l - 1][j]
    # Sum up all valid subsequences of length k
    for i in range(k - 1, n):
        total += dp[k - 1][i]
    return total

