def countWords(s, length):
    if length == 1:
        return 1
    count = 1
    if s[0] == s[1]:
        count *= 1
    else:
        count *= 2
    for j in range(1, length - 1):
        if s[j] == s[j - 1] and s[j] == s[j + 1]:
            count *= 1
        elif s[j] == s[j - 1] or s[j] == s[j + 1] or s[j - 1] == s[j + 1]:
            count *= 2
        else:
            count *= 3
    if s[length - 1] == s[length - 2]:
        count *= 1
    else:
        count *= 2
    return count

