def minPalPartion(s):
    n = len(s)
    # Initialize the matrices
    P = [[False] * n for _ in range(n)]
    C = [[0] * n for _ in range(n)]
    # Every single character is a palindrome
    for i in range(n):
        P[i][i] = True
        C[i][i] = 0
    # Consider all substring lengths starting from 2
    for L in range(2, n+1):
        for i in range(n - L + 1):
            j = i + L - 1  # Ending index of substring
            # Check if substring s[i:j+1] is palindrome
            if L == 2:
                P[i][j] = (s[i] == s[j])
            else:
                P[i][j] = (s[i] == s[j]) and P[i+1][j-1]
            # If palindrome, no cut needed
            if P[i][j]:
                C[i][j] = 0
            else:
                C[i][j] = float('inf')
                # Find minimum cuts by trying all partitions
                for k in range(i, j):
