def binaryMedian(m, r, c):
    min_val = float('inf')
    max_val = float('-inf')
    for i in range(r):
        if m[i][0] < min_val:
            min_val = m[i][0]
        if m[i][c-1] > max_val:
            max_val = m[i][c-1]
    desired = (r * c + 1) // 2
    while min_val < max_val:
        mid = min_val + (max_val - min_val) // 2
        place = 0
        for i in range(r):
            # Count the number of elements <= mid in the current row
            # bisect_right returns the insertion point after the last occurrence of mid
