def MinimumCost(cost, n, W):
    val = []
    wt = []
    for i in range(n):
        if cost[i] != -1:
            val.append(cost[i])
            wt.append(i + 1)
    n_available = len(val)
    # Initialize DP table with dimensions (n_available+1) x (W+1)
    dp = [[float('inf')] * (W + 1) for _ in range(n_available + 1)]
    # Base case: for all rows i from 1 to n_available, dp[i][0] = 0
    for i in range(1, n_available + 1):
        dp[i][0] = 0
    # Fill the DP table
    for i in range(1, n_available + 1):
        for j in range(1, W + 1):
