def solve(dp, a, low, high, turn):
    if low == high:
        return a[low] * turn
    if dp[low][high] != 0:
        return dp[low][high]
    left_choice = a[low] * turn + solve(dp, a, low + 1, high, turn + 1)
    right_choice = a[high] * turn + solve(dp, a, low, high - 1, turn + 1)
    dp[low][high] = max(left_choice, right_choice)
    return dp[low][high]

