def sumofsquare(n):
    # Create a 2D list (n+1) x (n+1)
    C = [[0] * (n + 1) for _ in range(n + 1)]
    # Build Pascal's Triangle up to row n
    for i in range(n + 1):
        for j in range(min(i, n) + 1):
            if j == 0 or j == i:
                C[i][j] = 1
            else:
                C[i][j] = C[i - 1][j - 1] + C[i - 1][j]
    # Sum squares of binomial coefficients in the n-th row
    total = 0
    for i in range(n + 1):
        total += C[n][i] * C[n][i]
    return total

